      { num: "九三", ci: "井渫不食，為我心惻，可用汲，王明並受其福", baihua: "水井清潔卻無人飲用，讓我心中難過，可以汲水，明智的君王大家都受到福澤。", situation: "已經準備好了，主動讓人知道你的價值。", tip: "準備好了，主動讓人知道你的價值，等待被使用。", action: "當你已經做好充分準備時，主動讓合適的人知道你的價值和能力，等待被正確地使用，不要讓準備白費。", taboo: "準備好了卻不讓人知道、讓才能被埋沒。", transition: "清潔的水井需要被發現和使用，才能真正發揮價值。" },
      { num: "六四", ci: "井甃，無咎", baihua: "用磚砌好水井，無災禍。", situation: "持續投資在自我提升和完善上，確保品質。", tip: "持續投資自我提升和完善，確保品質。", action: "持續投資在提升自己的能力和品質上，就像用磚砌好水井一樣，確保自身的穩固和品質。", taboo: "忽視自我提升和完善、讓品質下滑。", transition: "持續的自我完善是井卦中最重要的維護。" },
      { num: "九五", ci: "井洌寒泉食", baihua: "水井清澈，寒冷的泉水可以飲用。", situation: "達到最佳狀態，充分服務他人。", tip: "達到最佳狀態，充分服務他人。", action: "當你的能力和狀態達到最佳時，充分地服務和幫助他人，就像清澈的寒泉一樣，讓所有人都能受益。", taboo: "在最佳狀態時吝嗇服務。", transition: "井卦五爻是最佳狀態的完全服務。" },
      { num: "上六", ci: "井收勿幕，有孚元吉", baihua: "水井打好不要蓋上，有誠信則大吉。", situation: "開放無私地分享，以誠信帶來大吉。", tip: "開放無私地分享，以誠信帶來大吉。", action: "以開放和無私的心態分享你的資源和能力，不要封閉，誠信地讓所有需要的人都能受益，這帶來最大的吉利。", taboo: "封閉資源、不願無私分享。", transition: "井卦的終點是開放無私的分享，這是水井最高的價值體現。" }
